        return None
    root = TreeNode(preorder[0])
    stack = [root]
    i = 1
    while i < len(preorder):
        if stack and stack[-1].val > preorder[i]:
            stack[-1].left = TreeNode(preorder[i])
            stack.append(stack[-1].left)
        else:
